\begin{array}{l}
\text { A-3. }\\
\begin{aligned}
\int_{0}^{x} \frac{\operatorname{Arctan}(\pi x)}{x} \operatorname{Arctan} x d x & =\left.\int_{01}^{x} \frac{1}{x} \operatorname{Arctan}(u x)\right|_{u=1} ^{u=\pi} d x \\
& =\int_{0}^{x} \int_{1}^{\pi} \frac{1}{1+(x u)^{2}} d u d x=\int_{1}^{\pi} \int_{0}^{x} \frac{1}{1+(x u)^{2}} d x d u \\
& =\int_{1}^{\pi} \frac{1}{u} \cdot \frac{\pi}{2} d u=\frac{\pi}{2} \ln \pi
\end{aligned}
\end{array}

descriptive_long.question:
\[
\int_{0}^{\infty} \frac{\operatorname{Arctan}(\pi \mathrm{positivereal})-\operatorname{Arctan} 
\mathrm{positivereal}}{\mathrm{positivereal}} \, d\mathrm{positivereal}
\]

descriptive_long.solution:
\begin{array}{l}
\text { A-3. }\\
\begin{aligned}
\int_{0}^{\mathrm{positivereal}} \frac{\operatorname{Arctan}(\pi 
\mathrm{positivereal})}{\mathrm{positivereal}} \, \operatorname{Arctan} \mathrm{positivereal}
\, d\mathrm{positivereal} & =\left.\int_{01}^{\mathrm{positivereal}} \frac{1}{\mathrm{positivereal}} \, \operatorname{Arctan}(\mathrm{auxiliary}\,\mathrm{positivereal})\right|_{\mathrm{auxiliary}=1} ^{\mathrm{auxiliary}=\pi} d\mathrm{positivereal} \\
& =\int_{0}^{\mathrm{positivereal}} \int_{1}^{\pi} \frac{1}{1+(\mathrm{positivereal}\,\mathrm{auxiliary})^{2}} \, d\mathrm{auxiliary} \, d\mathrm{positivereal}=\int_{1}^{\pi} \int_{0}^{\mathrm{positivereal}} \frac{1}{1+(\mathrm{positivereal}\,\mathrm{auxiliary})^{2}} \, d\mathrm{positivereal} \, d\mathrm{auxiliary} \\
& =\int_{1}^{\pi} \frac{1}{\mathrm{auxiliary}} \cdot \frac{\pi}{2} \, d\mathrm{auxiliary}=\frac{\pi}{2} \ln \pi
\end{aligned}
\end{array}

